    return root

def find_min(root):
    while root and root.left:
        root = root.left
    return root

def delete(root, key):
    if root is None:
        return None
    if key < root.data:
        root.left = delete(root.left, key)
    elif key > root.data:
        root.right = delete(root.right, key)
    else:
        if root.left is None:
            return root.right
        if root.right is None:
            return root.left
        succ = find_min(root.right)
        root.data = succ.data
        root.right = delete(root.right, succ.data)
    return root

